const attendance = $('Fetch Attendance').first().json;
const leaves = $('Fetch Leaves').first().json;
const payroll = $('Fetch Payroll').first().json;

const attArr = Array.isArray(attendance) ? attendance : [];
const leaveArr = Array.isArray(leaves) ? leaves : [];
const payArr = Array.isArray(payroll) ? payroll : [];

const today = new Date().toISOString().split('T')[0];
const presentToday = attArr.filter(a => a.date === today && a.status === 'PRESENT').length;
const lateToday = attArr.filter(a => a.date === today && a.status === 'LATE').length;
const absentToday = attArr.filter(a => a.date === today && a.status === 'ABSENT').length;
const pendingLeaves = leaveArr.filter(l => l.status === 'PENDING').length;
const approvedLeaves = leaveArr.filter(l => l.status === 'APPROVED').length;
const pendingPayroll = payArr.filter(p => p.status === 'PENDING').length;
const paidPayroll = payArr.filter(p => p.status === 'PAID').length;

const content = '📊 **Daily HR Summary** — ' + today + '\n\n' +
  '📝 **Attendance Today**\n' +
  '  ✅ Present: ' + presentToday + '\n' +
  '  ⏰ Late: ' + lateToday + '\n' +
  '  ❌ Absent: ' + absentToday + '\n\n' +
  '🏖️ **Leave Requests**\n' +
  '  ⏳ Pending: ' + pendingLeaves + '\n' +
  '  ✅ Approved (all-time): ' + approvedLeaves + '\n\n' +
  '💰 **Payroll**\n' +
  '  ⏳ Pending: ' + pendingPayroll + '\n' +
  '  ✅ Paid: ' + paidPayroll + '\n\n' +
  '🤖 _Generated automatically by SynergyGig n8n_';

return [{ json: { content } }];
